                CASE WHEN @hs_invoice_source_Clear = 1 THEN NULL ELSE ISNULL(@hs_invoice_source, NULL) END,
                CASE WHEN @hs_store_payment_method_at_checkout_Clear = 1 THEN NULL ELSE ISNULL(@hs_store_payment_method_at_checkout, NULL) END,
                CASE WHEN @hs_recipient_company_address2_Clear = 1 THEN NULL ELSE ISNULL(@hs_recipient_company_address2, NULL) END,
                CASE WHEN @hs_title_Clear = 1 THEN NULL ELSE ISNULL(@hs_title, NULL) END,
                ISNULL(@__mj_integration_SyncStatus, 'Active'),
                CASE WHEN @__mj_integration_LastSyncedAt_Clear = 1 THEN NULL ELSE ISNULL(@__mj_integration_LastSyncedAt, NULL) END,
                CASE WHEN @__mj_integration_LastSyncedSnapshot_Clear = 1 THEN NULL ELSE ISNULL(@__mj_integration_LastSyncedSnapshot, NULL) END,
                CASE WHEN @__mj_integration_SyncMessage_Clear = 1 THEN NULL ELSE ISNULL(@__mj_integration_SyncMessage, NULL) END,
                @hs_object_id
        )
    -- return the new record from the base view, which might have some calculated fields
    SELECT * FROM [hubspot].[vwInvoices] WHERE [hs_object_id] = @hs_object_id
END
